import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, ShoppingCart, Filter, Tag } from 'lucide-react';
import { URL_CARPETA_IMAGENES } from '../utils/helpers';

const VistaCliente = () => {
  const [productos, setProductos] = useState([]);
  const [categoriaActiva, setCategoriaActiva] = useState('Todos');
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(true);

  // Categorías que coinciden con tu DICCIONARIO_PRODUCTOS
  const categorias = [
    'Todos', 'Almacén', 'Bebidas', 'Lácteos', 'Carnicería', 
    'Frutas y Verduras', 'Limpieza', 'Perfumería', 'Mascotas'
  ];

  useEffect(() => {
    fetchProductos();
  }, []);

  const fetchProductos = async () => {
    try {
      const res = await axios.get(`${process.env.REACT_APP_API_URL}/api/ofertas`);
      setProductos(res.data);
    } catch (error) {
      console.error("Error al cargar productos");
    } finally {
      setLoading(false);
    }
  };

  // Lógica de Filtrado
  const productosFiltrados = productos.filter(p => {
    const coincideCategoria = categoriaActiva === 'Todos' || p.categoria === categoriaActiva;
    const coincideBusqueda = p.producto.toLowerCase().includes(busqueda.toLowerCase());
    return coincideCategoria && coincideBusqueda;
  });

  return (
    <div style={containerStyle}>
      {/* HEADER DE BÚSQUEDA */}
      <div style={headerStyle}>
        <div style={searchBarWrapper}>
          <Search size={20} color="#94a3b8" />
          <input 
            style={searchInput} 
            placeholder="Buscar marca, producto o categoría..." 
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
          />
        </div>
        <div style={cartIconStyle}>
          <ShoppingCart size={24} />
          <span style={cartBadge}>0</span>
        </div>
      </div>

      {/* SELECTOR DE CATEGORÍAS (PASILLOS) */}
      <div style={scrollCategories}>
        {categorias.map(cat => (
          <button 
            key={cat} 
            onClick={() => setCategoriaActiva(cat)}
            style={categoriaActiva === cat ? catBtnActive : catBtn}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* GRILLA DE PRODUCTOS */}
      <div style={gridStyle}>
        {loading ? (
          <p>Cargando pasillos...</p>
        ) : productosFiltrados.length > 0 ? (
          productosFiltrados.map(prod => (
            <div key={prod._id} style={cardStyle}>
              <div style={imgWrapper}>
                <img 
                  src={`${URL_CARPETA_IMAGENES}${prod.publicId}.jpg`} 
                  alt={prod.producto}
                  style={imgStyle}
                  onError={(e) => { e.target.src = "https://via.placeholder.com/150?text=Sin+Imagen"; }}
                />
                {prod.precioViejo > prod.precioNuevo && (
                  <div style={discountTag}>
                    -{Math.round(((prod.precioViejo - prod.precioNuevo) / prod.precioViejo) * 100)}%
                  </div>
                )}
              </div>
              
              <div style={infoStyle}>
                <span style={catTag}>{prod.categoria}</span>
                <h4 style={prodTitle}>{prod.producto}</h4>
                <div style={priceWrapper}>
                  <span style={currentPrice}>${prod.precioNuevo}</span>
                  {prod.precioViejo > prod.precioNuevo && (
                    <span style={oldPrice}>${prod.precioViejo}</span>
                  )}
                </div>
                <button style={addBtn}>Agregar al carrito</button>
              </div>
            </div>
          ))
        ) : (
          <div style={noResults}>
            <Filter size={40} color="#cbd5e1" />
            <p>No encontramos productos en este pasillo.</p>
          </div>
        )}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const containerStyle = { padding: '20px', background: '#f8fafc', minHeight: '100vh', fontFamily: 'sans-serif' };
const headerStyle = { display: 'flex', gap: '15px', alignItems: 'center', marginBottom: '20px' };
const searchBarWrapper = { flex: 1, display: 'flex', alignItems: 'center', gap: '10px', background: 'white', padding: '12px', borderRadius: '15px', border: '1px solid #e2e8f0' };
const searchInput = { border: 'none', outline: 'none', width: '100%', fontSize: '1rem' };
const cartIconStyle = { position: 'relative', background: '#1e293b', color: 'white', padding: '12px', borderRadius: '15px' };
const cartBadge = { position: 'absolute', top: '-5px', right: '-5px', background: '#e67e22', color: 'white', fontSize: '0.7rem', padding: '2px 6px', borderRadius: '10px', fontWeight: 'bold' };

const scrollCategories = { display: 'flex', gap: '10px', overflowX: 'auto', paddingBottom: '15px', marginBottom: '20px' };
const catBtn = { padding: '10px 20px', borderRadius: '25px', border: '1px solid #e2e8f0', background: 'white', cursor: 'pointer', whiteSpace: 'nowrap', color: '#64748b', fontWeight: 'bold' };
const catBtnActive = { ...catBtn, background: '#e67e22', color: 'white', borderColor: '#e67e22' };

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '15px' };
const cardStyle = { background: 'white', borderRadius: '18px', border: '1px solid #e2e8f0', overflow: 'hidden', display: 'flex', flexDirection: 'column' };
const imgWrapper = { position: 'relative', width: '100%', height: '150px', background: '#f1f5f9' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'contain' };
const discountTag = { position: 'absolute', top: '10px', left: '10px', background: '#ef4444', color: 'white', fontSize: '0.7rem', fontWeight: 'bold', padding: '4px 8px', borderRadius: '8px' };

const infoStyle = { padding: '12px', display: 'flex', flexDirection: 'column', flex: 1 };
const catTag = { fontSize: '0.6rem', color: '#94a3b8', textTransform: 'uppercase', fontWeight: 'bold' };
const prodTitle = { fontSize: '0.85rem', margin: '5px 0', color: '#1e293b', height: '40px', overflow: 'hidden' };
const priceWrapper = { display: 'flex', alignItems: 'baseline', gap: '5px', marginBottom: '10px' };
const currentPrice = { fontSize: '1.2rem', fontWeight: '900', color: '#1e293b' };
const oldPrice = { fontSize: '0.8rem', color: '#94a3b8', textDecoration: 'line-through' };
const addBtn = { width: '100%', padding: '10px', background: '#f8fafc', border: '1px solid #e2e8f0', borderRadius: '10px', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 'bold', color: '#1e293b' };
const noResults = { gridColumn: '1/-1', textAlign: 'center', padding: '50px', color: '#94a3b8' };

export default VistaCliente;
